population.algorithm:
For each order, evaluate all existing assigns plus one potential new assign via trial insertion with rollback, selecting the insertion yielding minimal marginal cost increase, with deterministic assign ordering and mandatory fallback to a new assign if all attempts fail.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const maxTries = MAXASSIGNS
	for idx := range oris {
		bestIdx := -1
		bestDelta := math.MaxFloat64
		orderID := total_ship + idx
		ori := oris[idx]
		des := dess[idx]

		numExisting := dispatch.AssignsLen
		candidates := numExisting + 1
		if candidates > maxTries {
			candidates = maxTries
		}

		for i := 0; i < candidates; i++ {
			targetIdx := i
			if targetIdx >= numExisting {
				targetIdx = numExisting
			}

			if dispatch.Assigns[targetIdx].StationsLen == 0 && targetIdx != numExisting {
				continue
			}

			oldCost := dispatch.Assigns[targetIdx].Cost

			ok := dispatch.Assigns[targetIdx].AddShip(orderID, ori, des)
			if !ok || dispatch.Assigns[targetIdx].Cost < 0 {
				if ok {
					dispatch.Assigns[targetIdx].RemoveShip(orderID)
					dispatch.Assigns[targetIdx].GenRoute()
				}
				continue
			}

			newCost := dispatch.Assigns[targetIdx].Cost
			delta := newCost - oldCost
			dispatch.Assigns[targetIdx].RemoveShip(orderID)
			dispatch.Assigns[targetIdx].GenRoute()

			if delta < bestDelta {
				bestDelta = delta
				bestIdx = targetIdx
			}
		}

		finalIdx := bestIdx
		if finalIdx < 0 {
			finalIdx = numExisting
		}

		insertOK := dispatch.Assigns[finalIdx].AddShip(orderID, ori, des)
		if !insertOK || dispatch.Assigns[finalIdx].Cost < 0 {
			if insertOK {
				dispatch.Assigns[finalIdx].RemoveShip(orderID)
				dispatch.Assigns[finalIdx].GenRoute()
			}
			fallbackOK := dispatch.Assigns[numExisting].AddShip(orderID, ori, des)
			if !fallbackOK || dispatch.Assigns[numExisting].Cost < 0 {
				if fallbackOK {
					dispatch.Assigns[numExisting].RemoveShip(orderID)
					dispatch.Assigns[numExisting].GenRoute()
				}
			} else {
				if numExisting < MAXASSIGNS {
					dispatch.AssignsLen++
				}
			}
		} else {
			if finalIdx >= dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.AssignsLen++
			}
		}
		dispatch.Assigns[finalIdx].GenRoute()
	}
	dispatch.RenewnTotalCost()
	return dispatch

