func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	var rand_range [MAXASSIGNS]int
	var rand_limit int = 0 //记录有多少个有车的assign

	logger := zap.L().Named("Insert")

	// 生成随机序列 TODO: 有些车在时间触发过程中可能变空了
	for ii := range rand_range {
		rand_range[ii] = ii
		// 交换不空的解
		if ii < dispatch.AssignsLen && dispatch.Assigns[ii].StationsLen > 0 {
			rand_range[ii], rand_range[rand_limit] = rand_range[rand_limit], ii
			// 记录有多少个不空的解
			rand_limit += 1
		}
	}
	//由于不空的解都在前面，所以只需要打乱前面这部分
	rand.Shuffle(rand_limit, func(i, j int) {
		rand_range[i], rand_range[j] = rand_range[j], rand_range[i]
	})

	// 开始插入
	for jj := range oris {
		for _, ii := range rand_range {
			//尝试插入解
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {

				dispatch.Assigns[ii].Cost = -1

			} else {
				dispatch.Assigns[ii].GenRoute()

			}
			//插入失败
			if dispatch.Assigns[ii].Cost < 0 {
				//fmt.Println("inserted but not avaliable")
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			} else {
				//如果插入成功，并且插入了一辆空车，那么扩展一辆车
				if ii >= dispatch.AssignsLen {
					dispatch.AssignsLen += 1
				}
				break
			}
			// 应当一定有一辆车能插入成功,否则第assignslen也插入失败的话，说明该订单插不进去
			if ii >= dispatch.AssignsLen {
				logger.Warn(
					"Cannot Insert",
					zap.Int("ship", total_ship+jj),
					zap.Int("non_empty", rand_limit),
					zap.Int("assigns_len", dispatch.AssignsLen),
				)
				fmt.Println(oris[jj], dess[jj])
				dispatch.Assigns[dispatch.AssignsLen].PrettyPrint()
				//dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship + jj, oris[jj], dess[jj])
				//checkDispatch(&dispatch)
				break
			}
		}
	}
	dispatch.RenewnTotalCost()
	//XXX: 调查发现,insertion不会改变累计里程，是别的东西删除了累计里程
	return dispatch
}

population.algorithm:
Greedy insertion with randomized candidate order processing, evaluating each ship's insertion into all existing routes via simulated insertion rollback to pick minimal cost increase, falling back to new route creation if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderIndices := make([]int, len(oris))
	for i := range orderIndices {
		orderIndices[i] = i
	}
	rand.Shuffle(len(orderIndices), func(i, j int) {
		orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
	})
	for _, idx := range orderIndices {
		bestAssignIdx := -1
		bestCostDelta := math.MaxFloat64
		originalCosts := make([]float64, dispatch.AssignsLen+len(oris))
		for i := 0; i < dispatch.AssignsLen; i++ {
			originalCosts[i] = dispatch.Assigns[i].Cost
		}
		originalAssignsLen := dispatch.AssignsLen
		fallbackUsed := false
		for tryIdx := 0; tryIdx <= dispatch.AssignsLen; tryIdx++ {
			assignPtr := &dispatch.Assigns[tryIdx]
			savedState := originalCosts[tryIdx]
			success := assignPtr.AddShip(total_ship+idx, oris[idx], dess[idx])
			if success {
				assignPtr.GenRoute()
				costAfter := assignPtr.Cost
				costBefore := savedState
				delta := costAfter - costBefore
				if delta >= 0 && delta < bestCostDelta {
					bestCostDelta = delta
					bestAssignIdx = tryIdx
				}
				assignPtr.RemoveShip(total_ship + idx)
				assignPtr.Cost = savedState
				assignPtr.GenRoute()
			} else {
				if tryIdx == dispatch.AssignsLen {
					fallbackUsed = true
				}
			}
		}
		targetIdx := bestAssignIdx
		if targetIdx == -1 {
			targetIdx = dispatch.AssignsLen
			if fallbackUsed || targetIdx >= MAXASSIGNS {
				continue
			}
			dispatch.Assigns[targetIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
			dispatch.Assigns[targetIdx].GenRoute()
			dispatch.AssignsLen++
		} else {
			assignPtr := &dispatch.Assigns[targetIdx]
			assignPtr.AddShip(total_ship+idx, oris[idx], dess[idx])
			assignPtr.GenRoute()
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

