func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type trialRecord struct {
		assignIdx int
		costDelta float64
		success   bool
	}
	const INVALID_COST = 1e18

	for orderIdx := range oris {
		bestTrial := trialRecord{assignIdx: -1, costDelta: INVALID_COST, success: false}
		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx

		checkRange := dispatch.AssignsLen
		if checkRange == 0 {
			checkRange = 1
		}
		for candIdx := 0; candIdx <= checkRange; candIdx++ {
			if candIdx >= MAXASSIGNS {
				break
			}
			isNewEmpty := candIdx >= dispatch.AssignsLen
			var baseCost float64
			if isNewEmpty {
				baseCost = 0.0
			} else {
				baseCost = dispatch.Assigns[candIdx].Cost
			}
			savedState := dispatch.Assigns[candIdx]

			ok := dispatch.Assigns[candIdx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[candIdx].GenRoute()
				newCost := dispatch.Assigns[candIdx].Cost
				if newCost >= 0 {
					delta := newCost - baseCost
					if delta < bestTrial.costDelta {
						bestTrial.assignIdx = candIdx
						bestTrial.costDelta = delta
						bestTrial.success = true
					}
				}
			}
			dispatch.Assigns[candIdx] = savedState
			if !isNewEmpty {
				dispatch.Assigns[candIdx].GenRoute()
			}
		}

		insertIdx := -1
		if bestTrial.success && bestTrial.assignIdx >= 0 {
			insertIdx = bestTrial.assignIdx
		} else {
			insertIdx = dispatch.AssignsLen
			if insertIdx >= MAXASSIGNS {
				insertIdx = MAXASSIGNS - 1
			}
		}

		isNewEmptyFinal := insertIdx >= dispatch.AssignsLen
		ok := dispatch.Assigns[insertIdx].AddShip(shipID, ori, des)
		if ok {
			dispatch.Assigns[insertIdx].GenRoute()
			if isNewEmptyFinal && dispatch.Assigns[insertIdx].Cost >= 0 {
				dispatch.AssignsLen++
				if dispatch.AssignsLen > MAXASSIGNS {
					dispatch.AssignsLen = MAXASSIGNS
				}
			}
		} else {
			dispatch.Assigns[insertIdx].RemoveShip(shipID)
			dispatch.Assigns[insertIdx].GenRoute()
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				dispatch.Assigns[fallbackIdx].RemoveShip(shipID)
				ok2 := dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
				if ok2 {
					dispatch.Assigns[fallbackIdx].GenRoute()
