func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type trialRecord struct {
		assignIdx int
		costDelta float64
		success   bool
	}
	const INVALID_COST = 1e18

	for orderIdx := range oris {
		bestTrial := trialRecord{assignIdx: -1, costDelta: INVALID_COST, success: false}
		ori := oris[orderIdx]
		des := dess[orderIdx]
		shipID := total_ship + orderIdx

		checkRange := dispatch.AssignsLen
		if checkRange == 0 {
			checkRange = 1
		}
		for candIdx := 0; candIdx <= checkRange; candIdx++ {
			if candIdx >= MAXASSIGNS {
				break
			}
			isNewEmpty := candIdx >= dispatch.AssignsLen
			var baseCost float64
			if isNewEmpty {
				baseCost = 0.0
			} else {
				baseCost = dispatch.Assigns[candIdx].Cost
			}
			savedState := dispatch.Assigns[candIdx]

			ok := dispatch.Assigns[candIdx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[candIdx].GenRoute()
				newCost := dispatch.Assigns[candIdx].Cost
				if newCost >= 0 {
					delta := newCost - baseCost
					if delta < bestTrial.costDelta {
						bestTrial.assignIdx = candIdx
						bestTrial.costDelta = delta
						bestTrial.success = true
					}
				}
			}
			dispatch.Assigns[candIdx] = savedState
			if !isNewEmpty {
				dispatch.Assigns[candIdx].GenRoute()
			}
		}

		insertIdx := -1
		if bestTrial.success && bestTrial.assignIdx >= 0 {
			insertIdx = bestTrial.assignIdx
		} else {
			insertIdx = dispatch.AssignsLen
			if insertIdx >= MAXASSIGNS {
				insertIdx = MAXASSIGNS - 1
			}
		}

		isNewEmptyFinal := insertIdx >= dispatch.AssignsLen
		ok := dispatch.Assigns[insertIdx].AddShip(shipID, ori, des)
		if ok {
			dispatch.Assigns[insertIdx].GenRoute()
			if isNewEmptyFinal && dispatch.Assigns[insertIdx].Cost >= 0 {
				dispatch.AssignsLen++
				if dispatch.AssignsLen > MAXASSIGNS {
					dispatch.AssignsLen = MAXASSIGNS
				}
			}
		} else {
			dispatch.Assigns[insertIdx].RemoveShip(shipID)
			dispatch.Assigns[insertIdx].GenRoute()
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				dispatch.Assigns[fallbackIdx].RemoveShip(shipID)
				ok2 := dispatch.Assigns[fallbackIdx].AddShip(shipID, ori, des)
				if ok2 {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if dispatch.Assigns[fallbackIdx].Cost >= 0 {
						dispatch.AssignsLen++
						if dispatch.AssignsLen > MAXASSIGNS {
							dispatch.AssignsLen = MAXASSIGNS
						}
					}
				} else {
					dispatch.Assigns[fallbackIdx].RemoveShip(shipID)
					dispatch.Assigns[fallbackIdx].GenRoute()
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch
}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	var rand_range [MAXASSIGNS]int
	var rand_limit int = 0 //记录有多少个有车的assign

	logger := zap.L().Named("Insert")

	// 生成随机序列 TODO: 有些车在时间触发过程中可能变空了
	for ii := range rand_range {
		rand_range[ii] = ii
		// 交换不空的解
		if ii < dispatch.AssignsLen && dispatch.Assigns[ii].StationsLen > 0 {
			rand_range[ii], rand_range[rand_limit] = rand_range[rand_limit], ii
			// 记录有多少个不空的解
			rand_limit += 1
		}
	}
	//由于不空的解都在前面，所以只需要打乱前面这部分
	rand.Shuffle(rand_limit, func(i, j int) {
		rand_range[i], rand_range[j] = rand_range[j], rand_range[i]
	})

	// 开始插入
	for jj := range oris {
		for _, ii := range rand_range {
			//尝试插入解
			if !dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {

				dispatch.Assigns[ii].Cost = -1

			} else {
				dispatch.Assigns[ii].GenRoute()

			}
			//插入失败
			if dispatch.Assigns[ii].Cost < 0 {
				//fmt.Println("inserted but not avaliable")
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			} else {
				//如果插入成功，并且插入了一辆空车，那么扩展一辆车
				if ii >= dispatch.AssignsLen {
					dispatch.AssignsLen += 1
				}
				break
			}
			// 应当一定有一辆车能插入成功,否则第assignslen也插入失败的话，说明该订单插不进去
			if ii >= dispatch.AssignsLen {
				logger.Warn(
					"Cannot Insert",
					zap.Int("ship", total_ship+jj),
					zap.Int("non_empty", rand_limit),
					zap.Int("assigns_len", dispatch.AssignsLen),
				)
				fmt.Println(oris[jj], dess[jj])
				dispatch.Assigns[dispatch.AssignsLen].PrettyPrint()
				//dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship + jj, oris[jj], dess[jj])
				//checkDispatch(&dispatch)
				break
			}
		}
	}
	dispatch.RenewnTotalCost()
	//XXX: 调查发现,insertion不会改变累计里程，是别的东西删除了累计里程
	return dispatch
}

