			stationCurrentBackup[i] = dispatch.Assigns[i].StationCurrent
		}
		for tryIdx := 0; tryIdx < dispatch.AssignsLen; tryIdx++ {
			asgn := &dispatch.Assigns[tryIdx]
			oldCost := asgn.Cost
			if oldCost < 0 {
				continue
			}
			addOk := asgn.AddShip(id, ori, des)
			if !addOk {
				continue
			}
			asgn.GenRoute()
			newCost := asgn.Cost
			if newCost < 0 || newCost < oldCost-1e-9 {
				asgn.RemoveShip(id)
				asgn.GenRoute()
				continue
