        for i := 0; i < dispatch.AssignsLen; i++ {
            oldCost := dispatch.Assigns[i].Cost
            ok := dispatch.Assigns[i].AddShip(shipID, oris[idx], dess[idx])
            if ok {
                dispatch.Assigns[i].GenRoute()
                if dispatch.Assigns[i].Cost >= 0 {
                    costDelta := dispatch.Assigns[i].Cost - oldCost
                    if costDelta < bestCostDelta {
                        bestCostDelta = costDelta
                        bestAssignIdx = i
                    }
                }
            }
            // Restore assign to pre-trial state
            dispatch.Assigns[i] = *savedStates[i]
            dispatch.Assigns[i].GenRoute()
