func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		costDelta float64
		success   bool
	}
	orderCount := len(oris)
	for orderIdx := 0; orderIdx < orderCount; orderIdx++ {
		bestCandidate := candidate{assignIdx: -1, costDelta: 1e30, success: false}
		origAssignsLen := dispatch.AssignsLen
		totalEvalAssigns := origAssignsLen + 1
		for assignTryIdx := 0; assignTryIdx < totalEvalAssigns; assignTryIdx++ {
			currentAssignIdx := assignTryIdx
			if currentAssignIdx >= origAssignsLen {
				currentAssignIdx = origAssignsLen
				if dispatch.AssignsLen <= origAssignsLen {
					dispatch.AssignsLen++
				}
			}
			affectedAssign := &dispatch.Assigns[currentAssignIdx]
			savedState := *affectedAssign
			shipID := total_ship + orderIdx
			insertOk := affectedAssign.AddShip(shipID, oris[orderIdx], dess[orderIdx])
			if !insertOk {
				continue
			}
			affectedAssign.GenRoute()
			if affectedAssign.Cost < 0 {
				*affectedAssign = savedState
				affectedAssign.GenRoute()
				continue
			}
			oldCost := savedState.Cost
			if oldCost < 0 {
				oldCost = 0
			}
			delta := affectedAssign.Cost - oldCost
			isFeasible := true
			if assignTryIdx == origAssignsLen && dispatch.Assigns[currentAssignIdx].StationsLen == 0 {
				isFeasible = false
			}
			if isFeasible && delta < bestCandidate.costDelta {
				bestCandidate.assignIdx = currentAssignIdx
				bestCandidate.costDelta = delta
				bestCandidate.success = true
			}
			*affectedAssign = savedState
			affectedAssign.GenRoute()
		}
		targetAssignIdx := -1
		if bestCandidate.success {
			targetAssignIdx = bestCandidate.assignIdx
		} else {
			targetAssignIdx = dispatch.AssignsLen
			if dispatch.AssignsLen < MAXASSIGNS {
				dispatch.AssignsLen++
			}
		}
		finalTarget := &dispatch.Assigns[targetAssignIdx]
		insertDone := finalTarget.AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
		if !insertDone {
			for fi := 0; fi < dispatch.AssignsLen; fi++ {
				fallback := &dispatch.Assigns[fi]
				saveFb := *fallback
				ok := fallback.AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
				if ok {
					fallback.GenRoute()
					if fallback.Cost >= 0 {
						finalTarget = fallback
						targetAssignIdx = fi
						goto committed
					}
				}
				*fallback = saveFb
				fallback.GenRoute()
			}
			if dispatch.AssignsLen < MAXASSIGNS {
				newIdx := dispatch.AssignsLen
				dispatch.AssignsLen++
				finalTarget = &dispatch.Assigns[newIdx]
				finalTarget.AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
				targetAssignIdx = newIdx
			}
		}
committed:
		finalTarget.GenRoute()
	}
	dispatch.RenewnTotalCost()
	return dispatch

