Greedy insertion with cheapest incremental cost across all assignments using full trial-and-error rollback, falling back to new empty assign creation if needed.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderCount := len(oris)
	if orderCount == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	for shipIdx := 0; shipIdx < orderCount; shipIdx++ {
		bestAssignIdx := -1
		bestCostDelta := 0.0
		insertOk := false

		for tryAssignIdx := 0; tryAssignIdx < MAXASSIGNS; tryAssignIdx++ {
			if tryAssignIdx >= dispatch.AssignsLen && tryAssignIdx != dispatch.AssignsLen {
				continue
			}

			oldState := dispatch.Assigns[tryAssignIdx]

			addResult := dispatch.Assigns[tryAssignIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if !addResult {
				continue
			}
			dispatch.Assigns[tryAssignIdx].GenRoute()

			newCost := dispatch.Assigns[tryAssignIdx].Cost
			if newCost >= 0 {
				costBefore := oldState.Cost
				if costBefore < 0 {
					costBefore = 0
				}
				delta := newCost - costBefore
				if !insertOk || delta < bestCostDelta {
					bestCostDelta = delta
					bestAssignIdx = tryAssignIdx
					insertOk = true
				}
			}

			dispatch.Assigns[tryAssignIdx].RemoveShip(total_ship + shipIdx)
			dispatch.Assigns[tryAssignIdx].GenRoute()
			if dispatch.Assigns[tryAssignIdx].Cost < 0 {
				dispatch.Assigns[tryAssignIdx] = oldState
			}
		}

		targetAssignIdx := -1
		if insertOk {
			targetAssignIdx = bestAssignIdx
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				targetAssignIdx = dispatch.AssignsLen
				dispatch.AssignsLen++
			} else {
				for i := 0; i < MAXASSIGNS; i++ {
					if dispatch.Assigns[i].Cost <= 0 {
						targetAssignIdx = i
						break
					}
				}
				if targetAssignIdx == -1 {
					targetAssignIdx = 0
				}
			}
		}

		addResult := dispatch.Assigns[targetAssignIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
		if !addResult && targetAssignIdx == dispatch.AssignsLen-1 {
			okRetry := dispatch.Assigns[targetAssignIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
			if !okRetry {
				fallbackIdx := -1
				for fi := 0; fi < MAXASSIGNS; fi++ {
					temp := dispatch.Assigns[fi]
					trial := temp.AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
					if trial {
						dispatch.Assigns[fi] = temp
						dispatch.Assigns[fi].GenRoute()
						if dispatch.Assigns[fi].Cost >= 0 {
							fallbackIdx = fi
						}
						dispatch.Assigns[fi].RemoveShip(total_ship + shipIdx)
						dispatch.Assigns[fi].GenRoute()
						if dispatch.Assigns[fi].Cost < 0 {
							dispatch.Assigns[fi] = temp
						}
						if fallbackIdx >= 0 {
							break
						}
					}
				}
				if fallbackIdx >= 0 {
					targetAssignIdx = fallbackIdx
					dispatch.Assigns[targetAssignIdx].AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx])
				} else {
