func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type attempt struct {
		assignIdx int
		costDelta float64
		success   bool
	}
	for shipIdOffset, ori := range oris {
		des := dess[shipIdOffset]
		orderId := total_ship + shipIdOffset
		bestAttempt := attempt{-1, 0, false}
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedState := dispatch.Assigns[i].cloneForTrial()
			if dispatch.Assigns[i].AddShip(orderId, ori, des) {
				oldCost := dispatch.Assigns[i].Cost
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if !bestAttempt.success || delta < bestAttempt.costDelta {
						bestAttempt.assignIdx = i
						bestAttempt.costDelta = delta
						bestAttempt.success = true
					}
				}
				dispatch.Assigns[i].RestoreFromClone(savedState)
				dispatch.Assigns[i].GenRoute()
			}
		}
		if bestAttempt.success {
			targetIdx := bestAttempt.assignIdx
			if targetIdx >= 0 && targetIdx < MAXASSIGNS {
				dispatch.Assigns[targetIdx].AddShip(orderId, ori, des)
				dispatch.Assigns[targetIdx].GenRoute()
