func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    type candidate struct {
        assignIdx int
        costDelta float64
        feasible  bool
    }
    for jj := range oris {
        var candidates []candidate
        baseCost := dispatch.TotalCost
        savedStates := make([]float64, dispatch.AssignsLen)
        for i := 0; i < dispatch.AssignsLen; i++ {
            savedStates[i] = dispatch.Assigns[i].Cost
        }
        for ai := 0; ai < dispatch.AssignsLen; ai++ {
            added := dispatch.Assigns[ai].AddShip(total_ship+jj, oris[jj], dess[jj])
            if added {
                dispatch.Assigns[ai].GenRoute()
                if dispatch.Assigns[ai].Cost >= 0 {
                    costAfter := dispatch.AccumulatedCost
                    for k := 0; k < dispatch.AssignsLen; k++ {
                        costAfter += dispatch.Assigns[k].Cost
                    }
                    delta := costAfter - baseCost
                    candidates = append(candidates, candidate{assignIdx: ai, costDelta: delta, feasible: true})
                }
                dispatch.Assigns[ai].RemoveShip(total_ship + jj)
                dispatch.Assigns[ai].Cost = savedStates[ai]
                dispatch.Assigns[ai].GenRoute()
            }
        }
        chosen := -1
        minDelta := 0.0
        if len(candidates) > 0 {
            minDelta = candidates[0].costDelta
            chosen = candidates[0].assignIdx
            for _, c := range candidates[1:] {
                if c.costDelta < minDelta {
                    minDelta = c.costDelta
                    chosen = c.assignIdx
                }
            }
        }
        if chosen >= 0 {
            dispatch.Assigns[chosen].AddShip(total_ship+jj, oris[jj], dess[jj])
            dispatch.Assigns[chosen].GenRoute()
        } else {
            newIdx := dispatch.AssignsLen
            if newIdx < MAXASSIGNS {
                dispatch.Assigns[newIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
                dispatch.Assigns[newIdx].GenRoute()
                dispatch.AssignsLen++
            }
        }
    }
    dispatch.RenewnTotalCost()
    return dispatch
}
